/*
 * BTPopover — floating content panel.
 *
 * Used by Vue (BTPopoverContent.vue) and React (BTPopoverContent.tsx).
 * This single CSS file is shared between both framework packages.
 *
 * Figma node 2057-3539 · D - Popover
 *
 * Positioning is handled entirely in JS (position: fixed + inline top/left).
 * The panel starts at opacity: 0 so it is invisible while JS measures it;
 * adding .bt-popover-content--visible triggers the entrance animation.
 */

/* ── Trigger wrapper ──────────────────────────────────────────────── */
/*
 * display: contents makes the span layout-transparent — it does not
 * create its own box and does not affect the trigger element's sizing
 * or flow. Event bubbling still works through it normally.
 */
.bt-popover-trigger {
  display: contents;
}

/* ── Content panel ────────────────────────────────────────────────── */
.bt-popover-content {
  position: fixed;
  z-index: 1000;
  min-width: 200px;
  background: var(--bg-primary);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-md);
  padding: var(--space-lg);
  /* Subtle elevation — raw rgba allowed for non-tokenised overlays */
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.08), 0 1px 4px rgba(0, 0, 0, 0.04);
  box-sizing: border-box;
  outline: none;

  /* Hidden until JS positions and reveals the panel */
  opacity: 0;
}

/* Bare mode — strips visual chrome; embedded content provides its own card.
   Use with BTDropdownList, BTDropdownMenu, or any self-styled content. */
.bt-popover-content--bare {
  background: none;
  border: none;
  box-shadow: none;
  padding: 0;
  border-radius: 0;
}

.bt-popover-content--visible {
  animation: bt-popover-in 150ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

@keyframes bt-popover-in {
  from {
    opacity: 0;
    transform: scale(0.96);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

/**
 * BTPopover — public prop types.
 * Shared semantics between Vue (v-model:open) and React (open + onOpenChange).
 *
 * Figma node 2057-3539 · D - Popover
 */

export type BTPopoverSide = 'top' | 'bottom' | 'left' | 'right';
export type BTPopoverAlign = 'start' | 'center' | 'end';

export interface BTPopoverProps {
  /** Controlled open state. Vue: v-model:open. */
  open?: boolean;
  /** Emitted when open state changes. */
  onOpenChange?: (open: boolean) => void;
}

export interface BTPopoverTriggerProps {
  // no public props for Vue — the trigger wraps its slot transparently
}

export interface BTPopoverContentProps {
  /** Horizontal alignment of the panel relative to the trigger. Default: 'start'. */
  align?: BTPopoverAlign;
  /** Which side of the trigger to render on. Default: 'bottom'. */
  side?: BTPopoverSide;
  /** Gap in px between the trigger edge and the panel. Default: 8. */
  sideOffset?: number;
  /**
   * Strips the panel's visual chrome (background, border, shadow, padding,
   * border-radius) so that the embedded content provides its own card styling.
   *
   * Use when composing with components that already have a card look,
   * e.g. `BTDropdownList`, `BTDropdownMenu`.
   *
   * @default false
   * @example
   * ```vue
   * <BTPopoverContent align="end" side="bottom" bare>
   *   <BTDropdownList :items="items" @select="onSelect" />
   * </BTPopoverContent>
   * ```
   */
  bare?: boolean;
}
